{
  "mode": "method",
  "tests": [
    {
      "name": "valid_edit_link",
      "input": {
        "project_id": 123,
        "user_role": "admin"
      },
      "output": {
        "success": true,
        "message": "Edit link displayed correctly"
      },
      "notes": "Validates that an admin can see the edit link for a project."
    },
    {
      "name": "non_admin_user_access",
      "input": {
        "project_id": 123,
        "user_role": "viewer"
      },
      "output": {
        "success": false,
        "message": "Edit link not displayed for non-admin users"
      },
      "notes": "Ensures that non-admin users do not see the edit link."
    },
    {
      "name": "project_not_found",
      "input": {
        "project_id": 999,
        "user_role": "admin"
      },
      "output": {
        "success": false,
        "message": "Project not found"
      },
      "notes": "Tests the behavior when trying to edit a non-existent project."
    },
    {
      "name": "edit_link_for_multiple_projects",
      "input": [
        {
          "project_id": 123,
          "user_role": "admin"
        },
        {
          "project_id": 456,
          "user_role": "admin"
        }
      ],
      "output": [
        {
          "success": true,
          "message": "Edit link displayed for project 123"
        },
        {
          "success": true,
          "message": "Edit link displayed for project 456"
        }
      ],
      "notes": "Validates that edit links are displayed for multiple projects."
    },
    {
      "name": "edit_link_for_archived_project",
      "input": {
        "project_id": 789,
        "user_role": "admin"
      },
      "output": {
        "success": false,
        "message": "Edit link not available for archived projects"
      },
      "notes": "Checks that archived projects do not have an edit link."
    },
    {
      "name": "user_without_project_access",
      "input": {
        "project_id": 123,
        "user_role": "member",
        "access_level": "none"
      },
      "output": {
        "success": false,
        "message": "User does not have access to edit this project"
      },
      "notes": "Tests access control for users without project permissions."
    },
    {
      "name": "edit_link_with_special_characters",
      "input": {
        "project_id": 321,
        "user_role": "admin"
      },
      "output": {
        "success": true,
        "message": "Edit link displayed correctly with special characters"
      },
      "notes": "Validates that the edit link works with project names containing special characters."
    },
    {
      "name": "edit_link_for_inactive_user",
      "input": {
        "project_id": 123,
        "user_role": "admin",
        "user_status": "inactive"
      },
      "output": {
        "success": false,
        "message": "Inactive users cannot edit projects"
      },
      "notes": "Ensures that inactive users cannot access the edit link."
    }
  ],
  "assumptions": "User roles and project statuses are correctly defined in the system.",
  "notes": "Ensure to test with the latest version of the codebase."
}
